import type { CareerQuestion } from "./social-worker-questions";

export const socialWorkerQuestionsBatch25: CareerQuestion[] = [
  { id: "sw-1276", stem: "A social worker is using motivational interviewing with a client who is ambivalent about entering substance use treatment. Which technique is MOST appropriate to use first?", options: ["Confront the client about the consequences of continued use", "Express empathy through reflective listening to explore ambivalence", "Provide a list of treatment programs and insist on immediate enrollment", "Tell the client that treatment is mandatory"], correctIndex: 1, rationale: "Expressing empathy through reflective listening is a foundational principle of motivational interviewing. It builds rapport, validates the client's experience, and creates a safe space to explore ambivalence without judgment, which increases the likelihood of the client moving toward change.", difficulty: 1, category: "Communication & Interviewing", topic: "motivational interviewing", questionType: "CASE_VIGNETTE" },
  { id: "sw-1277", stem: "In motivational interviewing, 'developing discrepancy' refers to:", options: ["Highlighting inconsistencies in the client's story to catch lies", "Helping the client see the gap between their current behavior and their stated values or goals", "Disagreeing with the client's perspective", "Pointing out differences between the client and their peers"], correctIndex: 1, rationale: "Developing discrepancy is a core MI strategy that helps clients recognize the gap between where they are and where they want to be. When clients articulate this discrepancy themselves, intrinsic motivation for change increases without the worker needing to argue for change.", difficulty: 2, category: "Communication & Interviewing", topic: "motivational interviewing", questionType: "MCQ" },
  { id: "sw-1278", stem: "A social worker asks an elderly client, 'Suppose tonight while you sleep a miracle happens and tomorrow you wake up feeling the way you want to feel. What would be different?' This technique is from:", options: ["Cognitive behavioral therapy", "Psychoanalytic therapy", "Solution-focused therapy", "Dialectical behavior therapy"], correctIndex: 2, rationale: "The miracle question is a hallmark technique of solution-focused brief therapy (SFBT) developed by Steve de Shazer and Insoo Kim Berg. It helps clients envision their preferred future, bypass problem-focused thinking, and identify small achievable steps toward change.", difficulty: 1, category: "Gerontology", topic: "solution-focused therapy", questionType: "MCQ" },
  { id: "sw-1279", stem: "A social worker conducts an assessment using the person-in-environment (PIE) perspective. Which of the following BEST reflects this approach?", options: ["Focusing exclusively on the client's psychological symptoms", "Evaluating the client's functioning within the context of their social roles, environmental stressors, mental health, and physical health", "Administering a standardized personality test", "Conducting a home visit to inspect living conditions only"], correctIndex: 1, rationale: "The person-in-environment perspective is the defining framework of social work practice. It examines the individual within their environmental context, including social roles, relationships, community resources, economic conditions, and systemic factors, providing a holistic understanding rather than a narrow clinical focus.", difficulty: 1, category: "Community Practice & Advocacy", topic: "person-in-environment", questionType: "MCQ" },
  { id: "sw-1280", stem: "When applying the strengths perspective, a social worker working with a homeless veteran would FIRST:", options: ["Focus on the veteran's deficits to determine service eligibility", "Identify the veteran's existing skills, resources, resilience, and support networks", "Place the veteran in a shelter immediately without further assessment", "Diagnose the veteran's mental health condition"], correctIndex: 1, rationale: "The strengths perspective, developed by Dennis Saleebey, holds that every individual has strengths, capacities, and resources. Beginning with strengths identification empowers the client, builds rapport, and ensures that interventions build on existing assets rather than focusing solely on deficits.", difficulty: 2, category: "Community Practice & Advocacy", topic: "strengths perspective", questionType: "CASE_VIGNETTE" },
  { id: "sw-1281", stem: "A social worker discovers that a local policy disproportionately affects low-income families' access to mental health services. The MOST appropriate action aligned with social justice advocacy is to:", options: ["Accept the policy as beyond the social worker's scope", "Organize affected community members, gather data on the impact, and advocate for policy change through appropriate channels", "Refer clients to private practitioners", "File a personal complaint with the media"], correctIndex: 1, rationale: "Social justice advocacy is a core social work value codified in the NASW Code of Ethics. Organizing community members and using data-driven advocacy through appropriate channels represents ethical macro-level practice that addresses systemic barriers to service access for marginalized populations.", difficulty: 2, category: "Community Practice & Advocacy", topic: "social justice advocacy", questionType: "APPLIED_ETHICS" },
  { id: "sw-1282", stem: "Under HIPAA, a social worker may disclose protected health information without client consent in which of the following situations?", options: ["When a family member calls requesting information about the client's treatment", "When there is a court order requiring disclosure of specific records", "When a colleague from another agency asks about the client informally", "When the social worker wants to consult with a friend who is also a therapist"], correctIndex: 1, rationale: "HIPAA permits disclosure of protected health information without client authorization in specific circumstances, including compliance with a valid court order. The disclosure must be limited to the information specifically described in the court order. Family requests, informal colleague inquiries, and personal consultations do not meet HIPAA exceptions.", difficulty: 2, category: "Legislation & Policy Frameworks", topic: "HIPAA", questionType: "MCQ" },
  { id: "sw-1283", stem: "A school social worker suspects that a 7-year-old student is being physically abused based on unexplained bruising and the child's fearful behavior. The social worker should FIRST:", options: ["Confront the parents about the bruising", "File a report with the child protective services agency as a mandated reporter", "Wait to gather more evidence before reporting", "Consult with the school principal before making any report"], correctIndex: 1, rationale: "As a mandated reporter, the social worker is legally required to report suspected child abuse or neglect. The standard is reasonable suspicion, not confirmed evidence. Delaying a report to gather more evidence, confronting parents, or waiting for administrative approval could endanger the child and violate mandated reporting laws.", difficulty: 1, category: "Safeguarding & Vulnerable Populations", topic: "mandated reporting", questionType: "CASE_VIGNETTE" },
  { id: "sw-1284", stem: "In the developmental supervision model, a new social worker in their first year of practice would MOST benefit from:", options: ["Minimal oversight to encourage independence", "Highly structured supervision with clear guidelines, frequent feedback, direct observation, and skill-building focus", "Peer consultation only", "Self-directed learning without supervisor involvement"], correctIndex: 1, rationale: "Developmental supervision models (e.g., Stoltenberg) recognize that new practitioners need more structure, direct instruction, and frequent feedback. As competence increases, supervision transitions from directive to more consultative approaches, matching the supervisee's developmental stage.", difficulty: 2, category: "Interdisciplinary Collaboration", topic: "supervision models", questionType: "MCQ" },
  { id: "sw-1285", stem: "A social worker is evaluating a parenting program's effectiveness. Which program evaluation method would BEST determine whether the program caused observed changes in parenting skills?", options: ["A satisfaction survey distributed to participants", "A randomized controlled trial comparing participants to a control group using pre- and post-test measures", "Counting the number of participants who completed the program", "Collecting anecdotal success stories from staff"], correctIndex: 1, rationale: "A randomized controlled trial (RCT) is the gold standard for determining causation in program evaluation. By randomly assigning participants to treatment and control groups and measuring outcomes before and after, the evaluator can attribute changes to the program rather than extraneous variables.", difficulty: 3, category: "Community Practice & Advocacy", topic: "program evaluation", questionType: "MCQ" },
  { id: "sw-1286", stem: "A hospital social worker is developing a discharge plan for an elderly patient recovering from a hip fracture. The MOST important consideration is:", options: ["Discharging the patient as quickly as possible to free up the bed", "Assessing the patient's home environment, support system, rehabilitation needs, and ability to perform activities of daily living to ensure a safe transition", "Transferring the patient to a nursing home without consulting the patient", "Waiting until the patient's insurance company provides discharge instructions"], correctIndex: 1, rationale: "Effective discharge planning requires comprehensive assessment of the patient's functional status, home environment, caregiver availability, rehabilitation needs, and community resources. This patient-centered approach reduces readmission risk and supports optimal recovery while respecting the patient's autonomy and preferences.", difficulty: 2, category: "Gerontology", topic: "discharge planning", questionType: "CASE_VIGNETTE" },
  { id: "sw-1287", stem: "During a motivational interviewing session, a client says, 'I know I should stop drinking, but it helps me relax after work.' The social worker's BEST response is:", options: ["'You really need to find healthier ways to cope.'", "'On one hand, drinking helps you unwind, and on the other hand, you recognize it may be causing problems. Tell me more about that.'", "'How much are you drinking each day?'", "'Your drinking is clearly out of control.'"], correctIndex: 1, rationale: "This double-sided reflection is a core motivational interviewing technique that acknowledges both sides of the client's ambivalence without judgment. It demonstrates empathy, validates the client's experience, and invites further exploration of the discrepancy between current behavior and desired outcomes.", difficulty: 3, category: "Communication & Interviewing", topic: "motivational interviewing", questionType: "CASE_VIGNETTE" },
  { id: "sw-1288", stem: "In solution-focused therapy, 'exception questions' are used to:", options: ["Identify times when the client broke rules or norms", "Explore instances when the problem was absent or less severe to identify existing strengths and coping strategies", "Find exceptions to diagnostic criteria", "Challenge the client's perception of the problem"], correctIndex: 1, rationale: "Exception questions in SFBT help clients identify times when the problem did not occur or was less intense. These exceptions reveal existing strengths, resources, and coping strategies that can be amplified, shifting focus from problem saturation to solutions the client has already demonstrated.", difficulty: 2, category: "Communication & Interviewing", topic: "solution-focused therapy", questionType: "MCQ" },
  { id: "sw-1289", stem: "A social worker using the person-in-environment framework is assessing a single mother who lost her job. Which factor is LEAST relevant to this framework?", options: ["The mother's mental health status", "The availability of affordable childcare in the community", "The mother's blood type", "The family's access to public transportation"], correctIndex: 2, rationale: "The person-in-environment framework examines the interplay between individual functioning and environmental factors including social roles, community resources, economic conditions, and systemic barriers. Blood type is a medical detail unrelated to the social-environmental assessment unless specifically connected to a health condition affecting functioning.", difficulty: 1, category: "Community Practice & Advocacy", topic: "person-in-environment", questionType: "MCQ" },
  { id: "sw-1290", stem: "A social worker facilitating a support group for caregivers of people with dementia applies the strengths perspective by:", options: ["Focusing group discussion on the burdens and challenges of caregiving", "Encouraging members to share successful caregiving strategies, acknowledge their resilience, and identify personal and community resources", "Advising members to place their loved ones in institutional care", "Providing didactic lectures on dementia pathology"], correctIndex: 1, rationale: "The strengths perspective in group work involves recognizing and amplifying members' existing capacities, resilience, and resources. Encouraging caregivers to share successes and identify support networks empowers them, builds group cohesion, and creates a mutual aid environment that counters the deficit-focused narrative common in caregiver experiences.", difficulty: 3, category: "Group Work", topic: "strengths perspective", questionType: "CASE_VIGNETTE" },
  { id: "sw-1291", stem: "A social worker advocates for equitable access to healthcare for undocumented immigrants. This action is BEST described as:", options: ["Violating immigration law", "Social justice advocacy that aligns with the NASW Code of Ethics' commitment to challenging social injustice and advocating for vulnerable populations' access to resources", "Outside the scope of social work practice", "Political activism unrelated to professional duties"], correctIndex: 1, rationale: "The NASW Code of Ethics explicitly calls on social workers to pursue social change, particularly on behalf of vulnerable and oppressed populations. Advocating for equitable healthcare access regardless of immigration status aligns with the profession's core values of social justice, dignity and worth of the person, and the importance of human relationships.", difficulty: 3, category: "Community Practice & Advocacy", topic: "social justice advocacy", questionType: "APPLIED_ETHICS" },
  { id: "sw-1292", stem: "A social worker receives a subpoena for client records. Under HIPAA, the MOST appropriate first step is to:", options: ["Immediately release all requested records", "Consult with the agency's legal counsel to determine the validity of the subpoena and whether additional client authorization or a court order is needed", "Refuse to comply and destroy the records", "Contact the client's family to inform them"], correctIndex: 1, rationale: "Under HIPAA, a subpoena alone may not be sufficient for disclosure without client authorization or a court order. Consulting legal counsel ensures compliance with both HIPAA regulations and state law, protects client confidentiality, and determines the appropriate scope of any disclosure.", difficulty: 3, category: "Legislation & Policy Frameworks", topic: "HIPAA", questionType: "APPLIED_ETHICS" },
  { id: "sw-1293", stem: "A social worker treating an adult client learns that the client's elderly parent may be experiencing financial exploitation by another family member. The social worker's obligation as a mandated reporter requires:", options: ["Reporting only if the elderly parent is also the social worker's client", "Reporting the suspected elder abuse to the appropriate adult protective services agency regardless of whether the elderly parent is a client", "Confronting the family member suspected of exploitation", "Waiting for the elderly parent to request help"], correctIndex: 1, rationale: "Mandated reporting obligations for elder abuse apply when a professional has reasonable suspicion of abuse, neglect, or exploitation of a vulnerable adult. The obligation exists regardless of whether the elderly person is the reporter's direct client. Most states require mandated reporters to report suspected elder abuse to adult protective services.", difficulty: 3, category: "Safeguarding & Vulnerable Populations", topic: "mandated reporting", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1294", stem: "In clinical supervision, the 'parallel process' refers to:", options: ["Conducting supervision simultaneously with multiple supervisees", "A phenomenon where dynamics from the therapeutic relationship are unconsciously reenacted in the supervisory relationship, providing insight into both relationships", "Using the same treatment manual for all clients", "Documenting supervision and therapy notes identically"], correctIndex: 1, rationale: "Parallel process is a supervisory concept where patterns from the client-therapist relationship are unconsciously replicated in the supervisor-supervisee relationship. Recognizing parallel process provides valuable clinical information about the therapeutic relationship and helps the supervisee develop self-awareness and clinical skills.", difficulty: 3, category: "Interdisciplinary Collaboration", topic: "supervision models", questionType: "MCQ" },
  { id: "sw-1295", stem: "A logic model in program evaluation includes which of the following components?", options: ["Only the program budget and staffing plan", "Inputs, activities, outputs, short-term outcomes, and long-term outcomes that illustrate the theory of change underlying the program", "A list of client complaints", "Marketing materials for the program"], correctIndex: 1, rationale: "A logic model is a visual representation of a program's theory of change. It maps the logical connections between resources invested (inputs), what the program does (activities), direct products (outputs), and expected changes (short-term and long-term outcomes), providing a framework for program evaluation and accountability.", difficulty: 3, category: "Community Practice & Advocacy", topic: "program evaluation", questionType: "MCQ" },
  { id: "sw-1296", stem: "An older adult patient is being discharged after a stroke. The interdisciplinary team disagrees about the appropriate level of care. The social worker's PRIMARY role is to:", options: ["Defer to the physician's recommendation without question", "Advocate for the patient's preferences while facilitating communication among team members to develop a discharge plan that addresses safety, rehabilitation needs, and the patient's goals", "Arrange for the cheapest available option", "Discharge the patient home without services"], correctIndex: 1, rationale: "The social worker's role in discharge planning includes advocating for the patient's self-determination, facilitating interdisciplinary communication, assessing psychosocial needs, and ensuring the discharge plan is comprehensive and patient-centered. Effective discharge planning reduces readmissions and improves patient outcomes.", difficulty: 3, category: "Interdisciplinary Collaboration", topic: "discharge planning", questionType: "CASE_VIGNETTE" },
  { id: "sw-1297", stem: "Which of the following is an example of 'rolling with resistance' in motivational interviewing?", options: ["Arguing with the client about the need for change", "Acknowledging the client's reluctance without confrontation and reframing it as a normal part of the change process", "Ignoring the client's objections and continuing with the intervention plan", "Terminating the session when the client expresses resistance"], correctIndex: 1, rationale: "Rolling with resistance (now called 'responding to sustain talk') is a core MI principle. Rather than opposing or confronting resistance, the practitioner acknowledges it, avoids argumentation, and reframes it as natural ambivalence. This approach preserves the therapeutic alliance and allows the client to move toward change at their own pace.", difficulty: 3, category: "Communication & Interviewing", topic: "motivational interviewing", questionType: "MCQ" },
  { id: "sw-1298", stem: "A solution-focused therapist asks a client, 'On a scale of 1 to 10, where 10 means the problem is completely solved and 1 means it is the worst it has ever been, where are you today?' This is known as a:", options: ["Diagnostic assessment", "Scaling question", "Severity index", "Risk assessment"], correctIndex: 1, rationale: "Scaling questions are a fundamental SFBT technique that help clients quantify their progress, identify small changes, set achievable goals, and recognize their movement toward solutions. They provide a concrete framework for discussing abstract experiences and tracking progress over time.", difficulty: 1, category: "Communication & Interviewing", topic: "solution-focused therapy", questionType: "MCQ" },
  { id: "sw-1299", stem: "A social worker assesses a family using the person-in-environment framework and identifies that the family lives in a food desert with limited public transportation. This assessment addresses which system level?", options: ["Microsystem only", "Mesosystem only", "Exosystem and macrosystem levels, reflecting environmental and structural barriers that affect family functioning", "Individual psychological functioning"], correctIndex: 2, rationale: "The person-in-environment framework examines how broader environmental systems impact individual and family functioning. Food deserts and limited transportation represent exosystem (community-level resources and policies) and macrosystem (broader societal structures and inequities) factors that create barriers to well-being, demonstrating the ecological nature of social work assessment.", difficulty: 3, category: "Community Practice & Advocacy", topic: "person-in-environment", questionType: "MCQ" },
  { id: "sw-1300", stem: "A social worker in a community mental health center identifies that many clients share a common barrier: lack of affordable housing. Using the strengths perspective at the community level, the worker should:", options: ["Refer each client individually to a housing list", "Identify community assets, mobilize client voices, and collaborate with local organizations to advocate for affordable housing initiatives", "Accept housing scarcity as unchangeable", "Focus only on individual therapy goals"], correctIndex: 1, rationale: "The strengths perspective applied at the community level involves identifying existing community assets, mobilizing collective strengths, and empowering community members to advocate for systemic change. This macro-level application of the strengths perspective aligns with social work's dual focus on individual well-being and social conditions.", difficulty: 3, category: "Community Practice & Advocacy", topic: "strengths perspective", questionType: "APPLIED_ETHICS" },
  { id: "sw-1301", stem: "A social worker is advocating for policy changes to address racial disparities in the child welfare system. This is an example of:", options: ["Micro-level clinical practice", "Macro-level social justice advocacy aimed at addressing structural racism within institutional systems", "Exceeding professional boundaries", "Direct practice intervention"], correctIndex: 1, rationale: "Addressing racial disparities in child welfare systems through policy advocacy is a clear example of macro-level social justice advocacy. The NASW Code of Ethics mandates that social workers challenge social injustice, and addressing structural racism within institutions is a critical component of ethical social work practice.", difficulty: 2, category: "Community Practice & Advocacy", topic: "social justice advocacy", questionType: "APPLIED_ETHICS" },
  { id: "sw-1302", stem: "Under HIPAA's minimum necessary standard, when sharing client information for treatment purposes, a social worker should:", options: ["Share the entire client record with all treatment team members", "Share only the information that is reasonably necessary for the specific treatment purpose", "Refuse to share any information with other providers", "Require written authorization for every communication between treatment team members"], correctIndex: 1, rationale: "HIPAA's minimum necessary standard requires covered entities to limit disclosures of protected health information to the minimum amount reasonably necessary to accomplish the intended purpose. While HIPAA provides an exception for treatment disclosures, best practice still supports sharing only information relevant to the clinical purpose at hand.", difficulty: 3, category: "Legislation & Policy Frameworks", topic: "HIPAA", questionType: "MCQ" },
  { id: "sw-1303", stem: "A social worker suspects that a client's 3-year-old child is being neglected based on the child's poor hygiene, developmental delays, and the parent's statements about leaving the child unsupervised. The worker should:", options: ["Attempt to improve the parent's skills before reporting", "Immediately report the suspected neglect to child protective services as required by mandated reporting laws", "Document concerns and wait for additional evidence", "Discuss the situation with the parent first to give them a chance to improve"], correctIndex: 1, rationale: "Mandated reporting requires that suspected child abuse or neglect be reported immediately to the appropriate child protective services agency. The threshold is reasonable suspicion, not confirmed abuse. Delaying a report to provide interventions or gather additional evidence could place the child at continued risk and violates legal mandated reporting requirements.", difficulty: 2, category: "Safeguarding & Vulnerable Populations", topic: "mandated reporting", questionType: "CASE_VIGNETTE" },
  { id: "sw-1304", stem: "The integrative supervision model combines which three functions of supervision?", options: ["Planning, organizing, and directing", "Administrative, educational, and supportive functions that address organizational requirements, skill development, and worker well-being", "Assessment, intervention, and evaluation", "Intake, treatment, and discharge"], correctIndex: 1, rationale: "Kadushin's integrative supervision model identifies three core functions: administrative (ensuring organizational compliance, workload management, performance evaluation), educational (developing clinical knowledge and skills through case consultation and training), and supportive (addressing worker stress, preventing burnout, and promoting professional well-being). Effective supervision integrates all three functions.", difficulty: 3, category: "Interdisciplinary Collaboration", topic: "supervision models", questionType: "MCQ" },
  { id: "sw-1305", stem: "A social worker conducting a process evaluation of a teen pregnancy prevention program would focus on:", options: ["Whether teen pregnancy rates decreased after the program", "How the program was implemented, including fidelity to the curriculum, participant attendance, staff qualifications, and program reach", "The cost-effectiveness of the program", "Long-term health outcomes of participants"], correctIndex: 1, rationale: "Process evaluation examines how a program is implemented rather than its outcomes. It assesses fidelity to the program model, participant engagement, staff training, program reach, and implementation challenges. This type of evaluation helps determine whether the program was delivered as intended, which is essential for interpreting outcome results.", difficulty: 3, category: "Community Practice & Advocacy", topic: "program evaluation", questionType: "MCQ" },
  { id: "sw-1306", stem: "A social worker is planning discharge for a client with severe mental illness from an inpatient psychiatric facility. Which element is MOST critical to include in the discharge plan?", options: ["A list of local restaurants near the client's home", "Continuity of psychiatric medication management, outpatient therapy appointments, crisis contacts, and community support services", "The client's social media passwords for monitoring", "A detailed report of all incidents during hospitalization"], correctIndex: 1, rationale: "Effective psychiatric discharge planning must ensure continuity of care including medication management, outpatient treatment, crisis resources, and community supports. Research consistently shows that gaps in post-discharge care, particularly in the first 30 days, are associated with significantly increased risk of rehospitalization, crisis, and suicide.", difficulty: 2, category: "Interdisciplinary Collaboration", topic: "discharge planning", questionType: "CASE_VIGNETTE" },
  { id: "sw-1307", stem: "A social worker notices that a client in motivational interviewing is making 'change talk' statements such as 'I need to do something different.' The social worker should:", options: ["Ignore these statements and focus on the problem", "Reinforce and explore the change talk by asking elaboration questions such as 'What makes you feel that way?'", "Challenge the client's readiness for change", "Immediately create an action plan"], correctIndex: 1, rationale: "In motivational interviewing, change talk (desire, ability, reasons, need, commitment) signals movement toward change. The practitioner should reinforce change talk by reflecting it back, asking for elaboration, and affirming the client's statements. Research shows that increased change talk is predictive of behavior change outcomes.", difficulty: 3, category: "Communication & Interviewing", topic: "motivational interviewing", questionType: "CASE_VIGNETTE" },
  { id: "sw-1308", stem: "In solution-focused therapy, the therapist's stance is BEST described as:", options: ["Expert who diagnoses and prescribes treatment", "Curious collaborator who assumes the client is the expert on their own life and helps them identify and amplify solutions they have already used", "Neutral observer who avoids engagement", "Authority figure who directs the treatment process"], correctIndex: 1, rationale: "Solution-focused therapy positions the therapist as a curious, collaborative partner rather than an expert authority. The client is viewed as the expert on their own life, and the therapist's role is to ask questions that help the client identify existing strengths, past successes, and preferred futures, empowering client-driven change.", difficulty: 2, category: "Communication & Interviewing", topic: "solution-focused therapy", questionType: "MCQ" },
  { id: "sw-1309", stem: "A social worker at a senior center identifies an isolated older adult who has stopped attending social activities and shows signs of depression. Using the person-in-environment perspective, the worker assesses:", options: ["Only the client's depressive symptoms", "The client's mental health, physical health changes, recent losses, social network, transportation access, financial concerns, and environmental barriers to participation", "Whether the client should be placed in a nursing facility", "The client's insurance coverage for therapy"], correctIndex: 1, rationale: "The person-in-environment perspective requires examining the interplay between the individual and their environmental context. For an isolated older adult, this means assessing mental health alongside physical health changes, grief and loss, social support systems, practical barriers such as transportation, financial stressors, and community resources that could support re-engagement.", difficulty: 2, category: "Gerontology", topic: "person-in-environment", questionType: "CASE_VIGNETTE" },
  { id: "sw-1310", stem: "A social worker using the strengths perspective with an adolescent in foster care would:", options: ["Focus primarily on the trauma history and behavioral problems", "Help the adolescent identify personal talents, interests, supportive relationships, and past successes to build a plan for permanency and well-being", "Lower expectations based on the adolescent's difficult background", "Rely solely on standardized assessments to determine needs"], correctIndex: 1, rationale: "The strengths perspective with foster youth involves actively identifying and building on the adolescent's existing assets, including talents, interests, supportive relationships, and demonstrated resilience. This approach empowers youth, counters deficit-focused narratives common in child welfare, and supports positive identity development and self-efficacy.", difficulty: 2, category: "Safeguarding & Vulnerable Populations", topic: "strengths perspective", questionType: "CASE_VIGNETTE" },
  { id: "sw-1311", stem: "A social worker testifies before a legislative committee about the impact of proposed budget cuts on mental health services. This activity represents:", options: ["A violation of professional boundaries", "Social justice advocacy through legislative testimony, a core social work macro practice skill", "An inappropriate use of professional time", "Direct clinical practice"], correctIndex: 1, rationale: "Legislative testimony is a recognized form of social justice advocacy and macro social work practice. The NASW Code of Ethics specifically calls on social workers to engage in social and political action to promote conditions that fulfill basic human needs and to advocate for policies that support client populations.", difficulty: 1, category: "Community Practice & Advocacy", topic: "social justice advocacy", questionType: "MCQ" },
  { id: "sw-1312", stem: "A client requests that their social worker not document certain sensitive information in the clinical record. Under HIPAA and professional documentation standards, the social worker should:", options: ["Agree to omit the information entirely", "Explain that certain clinical information must be documented for continuity of care and legal requirements, while discussing what specific protections exist for sensitive information", "Document everything the client says regardless of the request", "Tell the client that HIPAA prevents any discussion about documentation"], correctIndex: 1, rationale: "Social workers must balance client concerns about documentation with professional and legal obligations. HIPAA provides certain protections for sensitive information (such as psychotherapy notes kept separate from the medical record), and the social worker should transparently discuss documentation requirements while respecting client concerns and explaining available safeguards.", difficulty: 4, category: "Documentation & Record Keeping", topic: "HIPAA", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1313", stem: "A social worker employed at a domestic violence shelter learns from a client that her partner has been threatening their children. The social worker must:", options: ["Keep this information confidential as it was shared in a therapeutic context", "Report the threats against the children to child protective services as a mandated reporter since children may be at risk of harm", "Wait until the client decides to report", "Contact the partner directly to address the threats"], correctIndex: 1, rationale: "Mandated reporting obligations supersede therapeutic confidentiality when children are at risk of harm. Threats against children by a violent partner constitute a reasonable suspicion of potential child abuse, triggering the mandated reporting requirement. The social worker should inform the client about the report and continue to support the client's safety planning.", difficulty: 3, category: "Safeguarding & Vulnerable Populations", topic: "mandated reporting", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1314", stem: "In reflective supervision, the PRIMARY focus is on:", options: ["Reviewing administrative tasks and case documentation", "Exploring the supervisee's emotional responses to clinical work, promoting self-awareness, and examining the impact of the therapeutic relationship on both worker and client", "Evaluating job performance metrics", "Assigning new cases to the supervisee"], correctIndex: 1, rationale: "Reflective supervision emphasizes the supervisee's internal experience of clinical work, including emotional reactions, countertransference, and the impact of the work on the practitioner. This model promotes self-awareness, deepens clinical understanding, prevents burnout, and enhances the quality of the therapeutic relationship.", difficulty: 3, category: "Interdisciplinary Collaboration", topic: "supervision models", questionType: "MCQ" },
  { id: "sw-1315", stem: "A needs assessment is conducted before implementing a new community health program. This is an example of which type of program evaluation?", options: ["Outcome evaluation", "Formative evaluation that gathers information to guide program design and implementation before the program begins", "Summative evaluation", "Cost-benefit analysis"], correctIndex: 1, rationale: "A needs assessment conducted before program implementation is a form of formative evaluation. It gathers data about the target population's needs, existing resources, and gaps in services to inform program design, ensure relevance, and increase the likelihood of the program's effectiveness in addressing community needs.", difficulty: 2, category: "Community Practice & Advocacy", topic: "program evaluation", questionType: "MCQ" },
  { id: "sw-1316", stem: "A social worker is coordinating discharge for a medically complex older adult. The patient's adult children disagree about the appropriate post-discharge care setting. The social worker's BEST approach is to:", options: ["Side with the child who visits most frequently", "Facilitate a family meeting to discuss the patient's medical needs, preferences, and available options while centering the patient's own wishes in the decision-making process", "Let the physician make the decision for the family", "Recommend the most expensive care option to demonstrate thoroughness"], correctIndex: 1, rationale: "Effective discharge planning for medically complex patients requires facilitating family communication while centering the patient's autonomy and preferences. Family meetings allow all stakeholders to share concerns, understand medical needs, explore options, and work toward consensus with the patient's wishes as the guiding principle.", difficulty: 3, category: "Gerontology", topic: "discharge planning", questionType: "CASE_VIGNETTE" },
  { id: "sw-1317", stem: "Which motivational interviewing strategy involves the social worker summarizing several things the client has said, linking them together to highlight the client's own arguments for change?", options: ["Confrontation", "A collecting summary that gathers the client's change talk and presents it back to reinforce motivation", "Advice-giving", "Diagnostic formulation"], correctIndex: 1, rationale: "Collecting summaries in MI strategically bring together multiple pieces of the client's change talk, presenting them as a coherent narrative that reinforces the client's own motivation for change. This technique uses the client's own words, which is more powerful than the practitioner's arguments for change.", difficulty: 4, category: "Communication & Interviewing", topic: "motivational interviewing", questionType: "MCQ" },
  { id: "sw-1318", stem: "A solution-focused therapist working with a couple in conflict asks, 'Tell me about a recent time when you handled a disagreement well together.' This is an example of:", options: ["A confrontation technique", "An exception-finding question that identifies times when the problem pattern was broken, revealing existing relationship strengths", "A paradoxical intervention", "A psychoeducation technique"], correctIndex: 1, rationale: "Exception-finding questions in SFBT help clients identify times when the presenting problem was absent or managed successfully. In couples work, asking about well-handled disagreements reveals existing communication and conflict-resolution skills that can be amplified and applied more consistently.", difficulty: 2, category: "Communication & Interviewing", topic: "solution-focused therapy", questionType: "CASE_VIGNETTE" },
  { id: "sw-1319", stem: "A social worker conducts a community assessment and finds that environmental racism has led to disproportionate pollution exposure in a minority neighborhood. This finding reflects the PIE framework's attention to:", options: ["Individual pathology", "The impact of macro-level environmental and structural factors on community health and well-being", "Clinical symptom presentation", "Family dynamics"], correctIndex: 1, rationale: "The person-in-environment framework explicitly addresses how macro-level structural factors including environmental racism, policy decisions, and institutional practices impact individual and community well-being. Identifying environmental racism as a determinant of health outcomes reflects PIE's ecological analysis of the reciprocal relationship between people and their environments.", difficulty: 4, category: "Community Practice & Advocacy", topic: "person-in-environment", questionType: "APPLIED_ETHICS" },
  { id: "sw-1320", stem: "A case manager applies the strengths perspective when working with a client diagnosed with schizophrenia by:", options: ["Focusing treatment planning on symptom elimination only", "Collaboratively identifying the client's personal goals, talents, social connections, and periods of wellness to develop a recovery-oriented service plan", "Assuming the client cannot make meaningful decisions due to the diagnosis", "Relying solely on medication management"], correctIndex: 1, rationale: "The strengths perspective applied in mental health recovery involves looking beyond the diagnosis to identify the whole person, including their goals, talents, relationships, and periods of wellness. Recovery-oriented practice using the strengths model empowers clients to take an active role in their treatment and build a meaningful life beyond illness management.", difficulty: 3, category: "Exam-Style Mixed Practice", topic: "strengths perspective", questionType: "CASE_VIGNETTE" },
  { id: "sw-1321", stem: "A social worker joins a coalition advocating for increased funding for early childhood education in underserved communities. This is an example of:", options: ["Direct clinical practice", "Coalition-based social justice advocacy that targets systemic inequities through collective action and policy change", "Case management", "Program evaluation"], correctIndex: 1, rationale: "Coalition-based advocacy represents macro-level social justice practice. By joining with other organizations and stakeholders, social workers amplify their advocacy impact, addressing systemic inequities in resource distribution that affect vulnerable populations. This aligns with the profession's ethical mandate to promote social justice.", difficulty: 1, category: "Community Practice & Advocacy", topic: "social justice advocacy", questionType: "MCQ" },
  { id: "sw-1322", stem: "A social worker discovers a data breach has occurred and client protected health information may have been compromised. Under HIPAA, the social worker's organization must:", options: ["Cover up the breach to avoid legal liability", "Notify affected individuals, the Department of Health and Human Services, and potentially the media (if the breach affects 500 or more individuals) within required timeframes", "Wait to see if anyone complains", "Only notify the organization's insurance company"], correctIndex: 1, rationale: "HIPAA's Breach Notification Rule requires covered entities to notify affected individuals without unreasonable delay (within 60 days), report to the HHS Secretary, and notify the media if the breach affects 500 or more individuals in a jurisdiction. Prompt notification allows affected individuals to take protective measures and is a legal requirement under HIPAA.", difficulty: 4, category: "Legislation & Policy Frameworks", topic: "HIPAA", questionType: "MCQ" },
  { id: "sw-1323", stem: "A social worker in a school setting observes that a student frequently comes to school hungry, wearing dirty clothes, and often falls asleep in class. The social worker should:", options: ["Provide the student with snacks and clean clothes from the school's supply", "Report suspected child neglect to child protective services and also connect the family with available resources such as food assistance and clothing programs", "Contact the parents to scold them about their child's appearance", "Document observations and wait for the situation to improve"], correctIndex: 1, rationale: "The observations describe potential indicators of child neglect, triggering the social worker's mandated reporting obligation. Simultaneously connecting the family with supportive resources reflects the dual approach of ensuring child safety while providing assistance to the family, consistent with a strengths-based and family-centered approach to child welfare.", difficulty: 2, category: "Safeguarding & Vulnerable Populations", topic: "mandated reporting", questionType: "CASE_VIGNETTE" },
  { id: "sw-1324", stem: "A supervisor notices a supervisee consistently avoids discussing cases involving end-of-life decisions. The supervisor should:", options: ["Assign more end-of-life cases to force exposure", "Gently explore the supervisee's discomfort, assess for personal triggers or grief responses, and provide supportive supervision to develop competence in this area", "Ignore the avoidance as a personal preference", "Reassign all end-of-life cases to other workers permanently"], correctIndex: 1, rationale: "Effective supervision addresses avoidance patterns by exploring underlying factors including personal triggers, grief, values conflicts, or skill deficits. The supportive function of supervision creates safety for the supervisee to examine these responses, while the educational function builds competence. Simply forcing exposure or permanently accommodating avoidance fails to promote professional development.", difficulty: 4, category: "Interdisciplinary Collaboration", topic: "supervision models", questionType: "CASE_VIGNETTE" },
  { id: "sw-1325", stem: "When conducting a summative program evaluation, the social worker is PRIMARILY interested in:", options: ["How the program can be improved during implementation", "Whether the program achieved its intended outcomes and should be continued, expanded, or discontinued", "The process of delivering program services", "Staff satisfaction with the program"], correctIndex: 1, rationale: "Summative evaluation occurs at the end of a program cycle and focuses on whether the program achieved its intended outcomes. It provides data for decisions about program continuation, expansion, replication, or termination. Unlike formative evaluation, which informs ongoing improvements, summative evaluation renders judgment on overall program effectiveness.", difficulty: 3, category: "Community Practice & Advocacy", topic: "program evaluation", questionType: "MCQ" },
  { id: "sw-1326", stem: "A patient with limited English proficiency is being discharged from the hospital. The social worker should ensure the discharge plan includes:", options: ["Discharge instructions in English only since they are standard forms", "Linguistically appropriate discharge instructions, interpreter services for follow-up appointments, and connection to culturally competent community resources", "A bilingual family member to translate all medical information", "Verbal instructions only since written materials may not be understood"], correctIndex: 1, rationale: "Effective discharge planning for patients with limited English proficiency requires culturally and linguistically appropriate services. Professional interpretation services, translated materials, and culturally competent resource connections are essential for patient safety, informed consent, and equitable access to care, as required by federal civil rights protections and accreditation standards.", difficulty: 3, category: "Interdisciplinary Collaboration", topic: "discharge planning", questionType: "CASE_VIGNETTE" },
  { id: "sw-1327", stem: "In motivational interviewing, the acronym OARS stands for:", options: ["Outcomes, Assessments, Reviews, Summaries", "Open-ended questions, Affirmations, Reflective listening, and Summaries", "Objectives, Actions, Results, Strategies", "Observations, Analysis, Recommendations, Solutions"], correctIndex: 1, rationale: "OARS represents the four core communication skills in motivational interviewing: Open-ended questions (invite elaboration), Affirmations (acknowledge strengths and efforts), Reflective listening (demonstrate understanding and deepen exploration), and Summaries (link ideas together and reinforce change talk). These skills form the foundation of the MI spirit.", difficulty: 1, category: "Communication & Interviewing", topic: "motivational interviewing", questionType: "MCQ" },
  { id: "sw-1328", stem: "A client in solution-focused therapy reports that they had a better week but dismisses the improvement as 'just luck.' The therapist's BEST response is:", options: ["Agree that it was probably luck", "Explore what the client did differently that week, highlighting their active role in creating the positive change", "Move on to another topic", "Confront the client about their pessimism"], correctIndex: 1, rationale: "In SFBT, the therapist helps the client take ownership of positive changes by exploring their active contribution. Asking what the client did differently reattributes the improvement from external luck to internal agency, building self-efficacy and identifying specific behaviors that can be deliberately repeated.", difficulty: 3, category: "Communication & Interviewing", topic: "solution-focused therapy", questionType: "CASE_VIGNETTE" },
  { id: "sw-1329", stem: "A social worker's person-in-environment assessment reveals that a client's depression worsened after the closure of the local community center where they volunteered. This demonstrates the PIE concept that:", options: ["Depression is solely a biological condition", "Individual well-being is deeply connected to environmental resources and social participation opportunities, and the loss of community infrastructure can significantly impact mental health", "The client should find a new hobby", "Environmental changes are irrelevant to mental health"], correctIndex: 1, rationale: "The person-in-environment framework recognizes that individual well-being is inextricable from environmental context. The closure of a meaningful community resource eliminated the client's social participation, sense of purpose, and social connections, demonstrating how environmental changes at the community level directly impact individual mental health.", difficulty: 2, category: "Community Practice & Advocacy", topic: "person-in-environment", questionType: "CASE_VIGNETTE" },
  { id: "sw-1330", stem: "A group facilitator using the strengths perspective in a group for people in recovery from substance use disorders would:", options: ["Have members focus primarily on sharing their worst moments of addiction", "Encourage members to share their recovery strategies, support networks, and personal achievements while also processing challenges", "Avoid discussing any difficulties to maintain a positive atmosphere", "Lecture the group about the dangers of substance use"], correctIndex: 1, rationale: "The strengths perspective in group work balances acknowledging challenges with actively amplifying recovery assets. Encouraging members to share strategies, support networks, and achievements builds collective efficacy, promotes mutual aid, and reinforces the recovery-oriented belief that individuals have the capacity for positive change.", difficulty: 2, category: "Group Work", topic: "strengths perspective", questionType: "CASE_VIGNETTE" },
  { id: "sw-1331", stem: "A social worker advocates for the passage of legislation requiring mental health parity in insurance coverage. This advocacy effort addresses:", options: ["An individual client's insurance denial", "A systemic policy barrier that creates inequitable access to mental health services, consistent with social justice principles and the NASW Code of Ethics", "A personal political interest unrelated to social work", "An administrative billing issue"], correctIndex: 1, rationale: "Mental health parity advocacy addresses structural inequity in healthcare access. The NASW Code of Ethics calls on social workers to advocate for policies that improve social conditions and promote social justice. Legislative advocacy for insurance parity removes systemic barriers that disproportionately affect people with mental health and substance use conditions.", difficulty: 2, category: "Legislation & Policy Frameworks", topic: "social justice advocacy", questionType: "APPLIED_ETHICS" },
  { id: "sw-1332", stem: "A social worker maintains HIPAA-compliant records by:", options: ["Keeping client files in an unlocked cabinet for easy staff access", "Using encrypted electronic records, securing physical files, limiting access to authorized personnel, and maintaining audit trails of record access", "Sharing login credentials with colleagues for convenience", "Storing records on a personal laptop without encryption"], correctIndex: 1, rationale: "HIPAA requires administrative, physical, and technical safeguards to protect electronic and physical health records. This includes encryption, secure storage, access controls, audit trails, and staff training on privacy practices. These safeguards protect client confidentiality and prevent unauthorized access to protected health information.", difficulty: 2, category: "Documentation & Record Keeping", topic: "HIPAA", questionType: "MCQ" },
  { id: "sw-1333", stem: "A therapist suspects that an elderly client's caregiver is withholding medication and food. The therapist is unsure whether this constitutes reportable abuse. The therapist should:", options: ["Wait for more conclusive evidence", "Report the suspected abuse to adult protective services, as mandated reporters are required to report when they have reasonable suspicion, not certainty, of abuse or neglect", "Ask the caregiver about the allegations directly", "Consult with a colleague and take no further action"], correctIndex: 1, rationale: "Mandated reporting laws require reporting based on reasonable suspicion, not confirmed evidence. Withholding medication and food from a dependent elderly person constitutes potential neglect or abuse. Delaying a report pending additional evidence may place the vulnerable adult at continued risk and violates the mandated reporter's legal obligation.", difficulty: 3, category: "Safeguarding & Vulnerable Populations", topic: "mandated reporting", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1334", stem: "Which supervision approach emphasizes the use of live observation, video recording, and immediate feedback to develop clinical skills?", options: ["Administrative supervision", "Competency-based supervision that uses direct observation methods to assess and develop specific clinical skills through structured feedback", "Peer supervision without any oversight", "Laissez-faire supervision"], correctIndex: 1, rationale: "Competency-based supervision emphasizes directly observing the supervisee's clinical work through live observation, video review, or co-therapy arrangements. This approach provides concrete, specific feedback on actual practice behaviors rather than relying solely on the supervisee's self-report, which enhances skill development and ensures fidelity to evidence-based practices.", difficulty: 4, category: "Interdisciplinary Collaboration", topic: "supervision models", questionType: "MCQ" },
  { id: "sw-1335", stem: "A social worker conducting an outcome evaluation of a domestic violence prevention program should measure:", options: ["Only the number of clients served", "Specific outcome indicators such as rates of revictimization, safety plan implementation, mental health improvement, and participant functioning at defined follow-up intervals", "Staff opinions about the program's effectiveness", "The program's budget utilization rate"], correctIndex: 1, rationale: "Outcome evaluation measures whether the program achieved its intended results by tracking specific, measurable indicators directly tied to program goals. For a domestic violence prevention program, relevant outcomes include safety, revictimization rates, mental health functioning, and empowerment indicators measured at defined intervals to assess both immediate and sustained program impact.", difficulty: 4, category: "Community Practice & Advocacy", topic: "program evaluation", questionType: "MCQ" },
  { id: "sw-1336", stem: "An elderly patient with early-stage dementia expresses a strong preference to be discharged home rather than to a skilled nursing facility. The social worker's BEST response is to:", options: ["Override the patient's preference based on the dementia diagnosis", "Assess the patient's decision-making capacity, explore home safety and support options, and develop a discharge plan that respects the patient's autonomy to the greatest extent possible while ensuring adequate safety and support", "Defer entirely to the family's wishes", "Delay discharge until the dementia progresses further"], correctIndex: 1, rationale: "Early-stage dementia does not automatically negate decision-making capacity. The social worker should assess capacity, explore how the patient's preference can be safely supported, and develop a plan that maximizes autonomy while ensuring adequate safety. This approach upholds the ethical principles of self-determination and dignity while fulfilling the duty to protect.", difficulty: 4, category: "Gerontology", topic: "discharge planning", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1337", stem: "When a client expresses 'sustain talk' in motivational interviewing, the practitioner should:", options: ["Argue against the client's reasons for not changing", "Acknowledge the sustain talk without amplifying it, then gently redirect toward exploring change talk", "Agree that change is not necessary", "End the session since the client is not ready"], correctIndex: 1, rationale: "Sustain talk represents the client's arguments for maintaining the status quo. In MI, the practitioner acknowledges sustain talk to demonstrate empathy and avoid triggering the righting reflex, while strategically redirecting the conversation to elicit and reinforce change talk. Arguing against sustain talk increases resistance and is counterproductive.", difficulty: 4, category: "Communication & Interviewing", topic: "motivational interviewing", questionType: "MCQ" },
  { id: "sw-1338", stem: "A social worker uses the 'best hopes' question in the first session: 'What are your best hopes for what we can achieve together?' This technique originates from:", options: ["Psychodynamic therapy", "Solution-focused brief therapy, which begins treatment by exploring the client's preferred outcomes rather than the problem history", "Exposure therapy", "Applied behavior analysis"], correctIndex: 1, rationale: "The 'best hopes' question is a solution-focused technique used at the beginning of therapy to establish the client's desired outcomes. By starting with preferred outcomes rather than problem exploration, SFBT creates a future-focused orientation that empowers the client and provides direction for therapeutic collaboration.", difficulty: 2, category: "Communication & Interviewing", topic: "solution-focused therapy", questionType: "MCQ" },
  { id: "sw-1339", stem: "A social worker assessing a refugee family uses the person-in-environment framework to consider:", options: ["Only the family's immigration status", "Pre-migration trauma, migration journey stressors, post-migration challenges including language barriers, cultural adjustment, employment, housing, discrimination, legal status, and access to culturally responsive community resources", "Whether the family should return to their home country", "Only the children's school performance"], correctIndex: 1, rationale: "The PIE framework applied to refugee families examines the full ecological context including pre-migration experiences, the migration journey, and post-migration stressors across multiple system levels. This comprehensive assessment identifies the complex interplay of individual, family, community, and systemic factors affecting the family's well-being and adaptation.", difficulty: 3, category: "Community Practice & Advocacy", topic: "person-in-environment", questionType: "CASE_VIGNETTE" },
  { id: "sw-1340", stem: "In group work, a social worker using the strengths perspective notices that one member consistently minimizes their own accomplishments. The worker should:", options: ["Ignore this pattern as it is not clinically significant", "Gently highlight the member's accomplishments and invite group feedback to help the member recognize their strengths and contributions", "Confront the member about their false modesty", "Tell the member to stop being negative"], correctIndex: 1, rationale: "The strengths perspective in group work involves actively helping members recognize their own capacities. Gently highlighting accomplishments and inviting positive group feedback uses the mutual aid function of the group to counter self-deprecation, builds the member's self-efficacy, and models strengths recognition for all group members.", difficulty: 3, category: "Group Work", topic: "strengths perspective", questionType: "CASE_VIGNETTE" },
  { id: "sw-1341", stem: "A social worker organizing a community forum on police accountability in a marginalized neighborhood is engaging in:", options: ["Clinical intervention", "Community-level social justice advocacy that empowers residents to participate in systems change and hold institutions accountable", "Illegal activity", "Individual case advocacy"], correctIndex: 1, rationale: "Organizing community forums on police accountability represents community-level social justice advocacy. This macro practice empowers marginalized community members to exercise voice, participate in democratic processes, and advocate for institutional accountability, consistent with social work's commitment to social justice and community empowerment.", difficulty: 2, category: "Community Practice & Advocacy", topic: "social justice advocacy", questionType: "APPLIED_ETHICS" },
  { id: "sw-1342", stem: "Under HIPAA, a client has the right to:", options: ["Demand that all their records be permanently destroyed", "Request access to their health records, request amendments to inaccurate information, and receive an accounting of disclosures of their protected health information", "Access other patients' records for comparison", "Prevent any documentation of their treatment"], correctIndex: 1, rationale: "HIPAA grants patients specific rights regarding their protected health information including the right to access and obtain copies of their records, request amendments to inaccurate information, receive an accounting of disclosures, and request restrictions on certain uses. These rights empower patients to participate in managing their health information.", difficulty: 2, category: "Legislation & Policy Frameworks", topic: "HIPAA", questionType: "MCQ" },
  { id: "sw-1343", stem: "A social worker suspects that an intellectually disabled adult client is being sexually abused by a staff member at a residential facility. The social worker should:", options: ["Interview the suspected staff member before reporting", "Immediately report to adult protective services and law enforcement, as this involves a vulnerable adult who may be unable to self-report", "Wait for the client to make a direct disclosure", "Report only to the facility's internal investigation unit"], correctIndex: 1, rationale: "Suspected sexual abuse of a vulnerable adult with intellectual disability requires immediate reporting to adult protective services and potentially law enforcement. The vulnerability of the population, the power differential with staff, and the client's potential inability to self-report make prompt external reporting essential for protection. Internal reporting alone is insufficient as it may create conflicts of interest.", difficulty: 4, category: "Safeguarding & Vulnerable Populations", topic: "mandated reporting", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1344", stem: "The discrimination model of supervision focuses on:", options: ["Identifying client discrimination experiences only", "Three supervisor roles (teacher, counselor, consultant) applied across three focus areas (intervention skills, conceptualization skills, personalization skills) based on the supervisee's needs", "Discriminating between qualified and unqualified supervisees", "Cultural discrimination in the workplace"], correctIndex: 1, rationale: "Bernard's discrimination model provides a flexible supervision framework where supervisors choose from three roles (teacher for instruction, counselor for processing personal reactions, consultant for collaborative problem-solving) across three focus areas depending on the supervisee's needs at any given moment. This adaptability makes it widely used in clinical supervision.", difficulty: 4, category: "Interdisciplinary Collaboration", topic: "supervision models", questionType: "MCQ" },
  { id: "sw-1345", stem: "When selecting outcome measures for program evaluation, a social worker should prioritize:", options: ["Measures that are easiest to administer regardless of relevance", "Valid, reliable instruments that directly measure the program's intended outcomes and are culturally appropriate for the target population", "Only qualitative feedback from staff", "Measures that will produce the most positive-looking results"], correctIndex: 1, rationale: "Rigorous program evaluation requires outcome measures that are psychometrically sound (valid and reliable), directly aligned with program goals, and culturally appropriate for the population being served. Selecting measures based on convenience or expected results undermines evaluation integrity and limits the usefulness of findings for program improvement.", difficulty: 4, category: "Community Practice & Advocacy", topic: "program evaluation", questionType: "MCQ" },
  { id: "sw-1346", stem: "A social worker creating a discharge plan for a client transitioning from a substance use treatment facility should include:", options: ["A warning letter about consequences of relapse", "Continuing care appointments, relapse prevention plan, peer support connections, housing arrangements, employment resources, and identification of recovery supports in the community", "Only the date and time of the next appointment", "A requirement that the client attend daily AA meetings"], correctIndex: 1, rationale: "Comprehensive discharge planning for substance use treatment requires addressing multiple recovery support domains including continuing care, relapse prevention, peer support, stable housing, employment, and community-based recovery resources. Research shows that effective continuing care planning significantly reduces relapse rates and supports sustained recovery.", difficulty: 2, category: "Exam-Style Mixed Practice", topic: "discharge planning", questionType: "CASE_VIGNETTE" },
  { id: "sw-1347", stem: "A social worker is using motivational interviewing with a client who has diabetes and is non-adherent with their medication regimen. The worker asks, 'What would you like to see happen with your health?' This is an example of:", options: ["Closed-ended questioning", "An open-ended question designed to elicit the client's own values and goals related to health behavior change", "A diagnostic interview question", "A compliance check"], correctIndex: 1, rationale: "Open-ended questions are a core OARS skill in motivational interviewing. This question invites the client to articulate their own health-related values and goals, which can then be linked to medication adherence. By eliciting the client's own motivation rather than prescribing behavior, the practitioner honors autonomy and supports self-directed change.", difficulty: 1, category: "Communication & Interviewing", topic: "motivational interviewing", questionType: "CASE_VIGNETTE" },
  { id: "sw-1348", stem: "In solution-focused therapy, 'pre-session change' refers to:", options: ["Changes the therapist makes to their office before a session", "Positive changes that clients often make between scheduling and attending their first appointment, which the therapist explores to identify existing client resources", "Pre-approved treatment plans", "Insurance pre-authorization"], correctIndex: 1, rationale: "SFBT therapists often ask about pre-session change (improvements noticed between scheduling and the first session) because research shows many clients begin to make positive changes once they have decided to seek help. Exploring these changes highlights client agency, identifies existing resources, and establishes a solution-focused orientation from the start.", difficulty: 3, category: "Communication & Interviewing", topic: "solution-focused therapy", questionType: "MCQ" },
  { id: "sw-1349", stem: "A social worker uses an ecomap to assess a client's social environment. The ecomap is a tool from the:", options: ["Medical model", "Person-in-environment framework that visually represents the client's relationships and connections to environmental systems, showing the nature and quality of those relationships", "Psychoanalytic approach", "Behaviorist tradition"], correctIndex: 1, rationale: "The ecomap, developed by Ann Hartman, is a visual assessment tool rooted in the person-in-environment framework. It diagrams the client's connections to external systems (family, work, school, healthcare, community, religion) and depicts the quality of these relationships (supportive, stressful, conflictual), providing a holistic ecological assessment.", difficulty: 1, category: "Community Practice & Advocacy", topic: "person-in-environment", questionType: "MCQ" },
  { id: "sw-1350", stem: "A strengths-based assessment differs from a traditional clinical assessment in that it:", options: ["Ignores presenting problems entirely", "Systematically explores client resources, coping abilities, support systems, and aspirations alongside challenges, creating a balanced picture that guides empowerment-oriented intervention planning", "Is less rigorous than traditional assessment", "Only uses standardized instruments"], correctIndex: 1, rationale: "Strengths-based assessment does not ignore problems but deliberately includes systematic exploration of strengths, resources, and coping capacities alongside challenges. This balanced approach creates a more complete picture of the client, identifies assets for intervention planning, and empowers the client by recognizing their existing competencies and resilience.", difficulty: 2, category: "Exam-Style Mixed Practice", topic: "strengths perspective", questionType: "MCQ" },
  { id: "sw-1351", stem: "A social worker discovers that an agency policy requires reporting all undocumented clients to immigration authorities. This policy conflicts with social work ethics. The worker should:", options: ["Comply with the policy without question", "Advocate for changing the policy through appropriate channels, citing the NASW Code of Ethics and the profession's commitment to protecting vulnerable populations from harm", "Resign immediately", "Report all undocumented clients as required"], correctIndex: 1, rationale: "When agency policies conflict with social work ethical obligations, practitioners have a responsibility to work toward changing those policies. The NASW Code of Ethics requires social workers to advocate for policies that protect client well-being and to challenge social injustice, particularly for vulnerable and oppressed populations.", difficulty: 4, category: "Community Practice & Advocacy", topic: "social justice advocacy", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1352", stem: "A social worker receives a phone call from a client's employer asking whether the client is receiving mental health treatment. Under HIPAA, the social worker should:", options: ["Confirm that the client is in treatment but provide no other details", "Decline to confirm or deny the client's treatment status without a valid written authorization from the client", "Provide a summary of the client's diagnosis and treatment plan", "Tell the employer to contact the client directly"], correctIndex: 1, rationale: "Under HIPAA, even confirming whether an individual is receiving treatment constitutes a disclosure of protected health information. Without a valid written authorization from the client, the social worker should not confirm or deny treatment status to an employer, as doing so would violate HIPAA privacy regulations.", difficulty: 3, category: "Legislation & Policy Frameworks", topic: "HIPAA", questionType: "CASE_VIGNETTE" },
  { id: "sw-1353", stem: "A social worker who is also a mandated reporter learns during couples therapy that one partner has been physically assaulting the other in front of their minor children. The social worker must:", options: ["Maintain confidentiality as this is a couples therapy session", "Report to child protective services because children witnessing domestic violence may constitute child maltreatment under mandated reporting laws", "Refer the couple to a domestic violence specialist and take no other action", "Address the violence only within the therapy context"], correctIndex: 1, rationale: "In many jurisdictions, children's exposure to domestic violence is recognized as a form of child maltreatment. As a mandated reporter, the social worker must report to child protective services when children are at risk of harm, including exposure to violence. This obligation supersedes therapeutic confidentiality and should be addressed transparently with the clients.", difficulty: 4, category: "Safeguarding & Vulnerable Populations", topic: "mandated reporting", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1354", stem: "In group supervision, the PRIMARY advantage over individual supervision is:", options: ["It is less expensive for the agency", "It provides multiple perspectives on clinical cases, normalizes common challenges, promotes peer learning, and develops collaborative practice skills", "It requires less preparation time", "It allows the supervisor to avoid individual accountability"], correctIndex: 1, rationale: "Group supervision offers unique benefits beyond cost efficiency, including exposure to diverse perspectives, normalization of clinical challenges, peer learning, development of consultation skills, and building a professional community of practice. These elements enhance clinical development in ways that complement individual supervision.", difficulty: 3, category: "Group Work", topic: "supervision models", questionType: "MCQ" },
  { id: "sw-1355", stem: "A social worker uses a theory of change to guide program evaluation. A theory of change:", options: ["Is the same as a program budget", "Articulates the causal mechanisms and assumptions underlying how program activities are expected to lead to desired outcomes, providing a roadmap for both implementation and evaluation", "Is only relevant for large-scale government programs", "Replaces the need for data collection"], correctIndex: 1, rationale: "A theory of change describes the hypothesized causal pathway from program activities to intended outcomes, including underlying assumptions and contextual factors. It guides program evaluation by identifying key indicators to measure, critical assumptions to test, and the logical connections between program components and expected results.", difficulty: 4, category: "Community Practice & Advocacy", topic: "program evaluation", questionType: "MCQ" },
  { id: "sw-1356", stem: "A social worker is planning discharge for a geriatric patient who lives alone and has no family support. The MOST appropriate action is to:", options: ["Discharge the patient home with written instructions only", "Conduct a comprehensive assessment of the patient's functional abilities and connect them with home health services, meals on wheels, medical alert systems, and community-based aging services", "Place the patient in a nursing home against their wishes", "Delay discharge indefinitely until a family member can be located"], correctIndex: 1, rationale: "Discharge planning for isolated older adults requires creative identification and coordination of community resources to ensure safety and support independence. A comprehensive functional assessment guides service connections including home health, nutrition programs, safety technology, and aging services that can substitute for informal family support.", difficulty: 2, category: "Gerontology", topic: "discharge planning", questionType: "CASE_VIGNETTE" },
  { id: "sw-1357", stem: "When using motivational interviewing with an adolescent client, the social worker should be especially mindful of:", options: ["Using authority to direct the adolescent toward change", "Respecting the adolescent's autonomy and developmental need for independence while exploring ambivalence in a non-judgmental, collaborative manner", "Involving the parents in every MI session", "Using the same techniques as with adult clients without modification"], correctIndex: 1, rationale: "MI with adolescents requires heightened attention to autonomy, as adolescents are developmentally oriented toward independence and are particularly sensitive to perceived control or judgment. The MI spirit of collaboration, evocation, and autonomy support aligns well with adolescent developmental needs when the practitioner adapts language and approach accordingly.", difficulty: 3, category: "Communication & Interviewing", topic: "motivational interviewing", questionType: "CASE_VIGNETTE" },
  { id: "sw-1358", stem: "A solution-focused therapist ends each session by:", options: ["Assigning homework from a manual", "Offering compliments about the client's strengths and efforts, and suggesting an observation or behavioral task that builds on the session's solutions", "Summarizing everything that is wrong in the client's life", "Scheduling the next appointment without further comment"], correctIndex: 1, rationale: "SFBT session endings typically include genuine compliments that reinforce client strengths and efforts, followed by a suggestion or experiment that encourages the client to notice or do more of what is working. This ending structure reinforces a solution-focused orientation, validates the client, and provides direction between sessions.", difficulty: 3, category: "Communication & Interviewing", topic: "solution-focused therapy", questionType: "MCQ" },
  { id: "sw-1359", stem: "A genogram is a person-in-environment assessment tool that:", options: ["Maps community resources available to the client", "Diagrams multigenerational family patterns including relationships, medical history, mental health conditions, substance use, and behavioral patterns to identify intergenerational themes", "Measures individual psychological functioning", "Tracks client progress over time"], correctIndex: 1, rationale: "The genogram is a visual assessment tool from the PIE tradition that maps multigenerational family structure and patterns. It reveals intergenerational themes including relationship dynamics, health conditions, mental illness, substance use, and behavioral patterns that inform understanding of the client's current functioning within their family system context.", difficulty: 1, category: "Community Practice & Advocacy", topic: "person-in-environment", questionType: "MCQ" },
  { id: "sw-1360", stem: "A community organization uses a strengths-based community development approach. This means:", options: ["Focusing on what the community lacks to justify funding requests", "Building on existing community assets, resident leadership, cultural resources, and local organizations to address community needs from within rather than imposing external solutions", "Hiring outside experts to solve community problems", "Conducting a deficit-based needs assessment"], correctIndex: 1, rationale: "Strengths-based community development, informed by Kretzmann and McKnight's asset-based community development model, identifies and mobilizes existing community assets including resident skills, local associations, institutions, physical resources, and cultural strengths. This approach empowers communities to drive their own change rather than depending on external experts and deficit-based interventions.", difficulty: 2, category: "Community Practice & Advocacy", topic: "strengths perspective", questionType: "MCQ" },
  { id: "sw-1361", stem: "A social worker documents a session using the SOAP format. The 'A' section should contain:", options: ["The client's reported symptoms", "The social worker's professional assessment, clinical impressions, analysis of the client's progress, and diagnostic formulations based on the subjective and objective data", "A list of appointments scheduled", "The client's address and insurance information"], correctIndex: 1, rationale: "In SOAP documentation, the Assessment section contains the clinician's professional analysis, clinical impressions, diagnostic formulations, and evaluation of client progress. It synthesizes the Subjective (client-reported) and Objective (clinician-observed) data into a clinical judgment that informs the Plan section.", difficulty: 1, category: "Documentation & Record Keeping", topic: "discharge planning", questionType: "MCQ" },
  { id: "sw-1362", stem: "A social worker is concerned that a proposed city zoning change would displace low-income residents from affordable housing. The MOST appropriate social justice advocacy response is to:", options: ["Accept the zoning change as a governmental decision beyond social work influence", "Research the impact, organize affected residents, build coalitions with housing advocacy groups, and present testimony to the zoning board about the disproportionate impact on vulnerable populations", "File a personal lawsuit against the city", "Advise clients to move before the change takes effect"], correctIndex: 1, rationale: "Effective social justice advocacy against displacement involves evidence-based research, community organizing, coalition building, and direct engagement with decision-making bodies. This multi-strategy approach amplifies affected residents' voices, presents data-driven arguments, and builds collective power to influence policy outcomes on behalf of vulnerable populations.", difficulty: 3, category: "Community Practice & Advocacy", topic: "social justice advocacy", questionType: "APPLIED_ETHICS" },
  { id: "sw-1363", stem: "HIPAA's psychotherapy notes provision means that:", options: ["All therapy notes are automatically shared with insurance companies", "Notes from individual or group psychotherapy sessions that are kept separate from the medical record receive additional protection and generally require specific patient authorization before disclosure, even for treatment purposes", "Psychotherapy notes are not protected by HIPAA", "Only psychiatrists' notes are protected"], correctIndex: 1, rationale: "HIPAA provides enhanced protection for psychotherapy notes (defined as notes documenting the contents of counseling sessions, kept separate from the medical record). Unlike general medical records, psychotherapy notes require specific written authorization from the patient before disclosure, even for treatment, payment, or healthcare operations purposes, with limited exceptions.", difficulty: 4, category: "Documentation & Record Keeping", topic: "HIPAA", questionType: "MCQ" },
  { id: "sw-1364", stem: "A teacher reports to a social worker that a student disclosed being hit at home but later recanted the statement. The social worker should:", options: ["Dismiss the concern since the child recanted", "Report to child protective services because the initial disclosure creates reasonable suspicion of abuse, and recantation is common among abused children due to fear, loyalty, or pressure", "Investigate independently by interviewing the parents", "Wait for the child to make another disclosure"], correctIndex: 1, rationale: "Recantation of abuse disclosures is well-documented in child abuse research and often results from fear, pressure, or loyalty conflicts. The initial disclosure creates reasonable suspicion sufficient to trigger mandated reporting obligations. The recantation does not eliminate the concern and should not prevent a report to child protective services.", difficulty: 4, category: "Safeguarding & Vulnerable Populations", topic: "mandated reporting", questionType: "CASE_VIGNETTE" },
  { id: "sw-1365", stem: "A new supervisor struggles with balancing the evaluative and supportive functions of supervision. The BEST approach is to:", options: ["Eliminate evaluation to maintain the therapeutic alliance with the supervisee", "Transparently discuss the dual role, establish clear expectations, use evaluation as a developmental tool, and create a supervision environment where feedback is ongoing and growth-oriented rather than punitive", "Focus only on evaluation since it is the primary purpose of supervision", "Let the supervisee choose which function they prefer"], correctIndex: 1, rationale: "Effective supervision integrates evaluative and supportive functions through transparency, clear expectations, and a developmental orientation. When evaluation is framed as a growth tool within a supportive relationship, the apparent tension between these functions diminishes. Ongoing feedback normalizes evaluation as part of professional development rather than a threatening process.", difficulty: 4, category: "Interdisciplinary Collaboration", topic: "supervision models", questionType: "CASE_VIGNETTE" },
  { id: "sw-1366", stem: "Participatory action research in program evaluation involves:", options: ["Researchers conducting evaluation without stakeholder input", "Engaging program participants and community members as co-researchers who help design, conduct, and interpret the evaluation, ensuring findings are relevant and actionable for the community", "Only using quantitative data", "Hiring an external evaluator with no community contact"], correctIndex: 1, rationale: "Participatory action research democratizes the evaluation process by involving program participants and community members as co-researchers. This approach ensures evaluation questions are community-driven, methods are culturally appropriate, findings are relevant to stakeholders, and results are more likely to be used for program improvement and community action.", difficulty: 4, category: "Community Practice & Advocacy", topic: "program evaluation", questionType: "MCQ" },
  { id: "sw-1367", stem: "A social worker develops a discharge plan for a client leaving a residential mental health program. Which element demonstrates person-centered discharge planning?", options: ["A standardized plan identical to all other clients' plans", "A plan developed collaboratively with the client that reflects their personal recovery goals, preferred services, cultural considerations, and natural support systems", "A plan created solely by the treatment team without client input", "A plan that focuses only on medication compliance"], correctIndex: 1, rationale: "Person-centered discharge planning involves active client participation in identifying goals, preferred services, and support systems. Collaborative planning respects client autonomy, incorporates cultural considerations, leverages natural supports, and increases the likelihood of engagement with post-discharge services because the plan reflects the client's own priorities and values.", difficulty: 2, category: "Exam-Style Mixed Practice", topic: "discharge planning", questionType: "CASE_VIGNETTE" },
  { id: "sw-1368", stem: "A social worker using motivational interviewing with a group of adolescents in a substance use prevention program adapts MI by:", options: ["Using confrontation to shock the adolescents into compliance", "Incorporating peer interaction, using developmentally appropriate language, emphasizing autonomy, and creating opportunities for adolescents to explore values and generate their own reasons for healthy choices", "Lecturing about the dangers of substance use", "Requiring parents to attend all sessions"], correctIndex: 1, rationale: "Adapting MI for adolescent group settings involves leveraging peer influence positively, using age-appropriate language, emphasizing autonomy (critical for adolescent development), and creating interactive opportunities for self-exploration. The MI spirit of collaboration and evocation is particularly effective with adolescents who respond poorly to authoritarian approaches.", difficulty: 3, category: "Group Work", topic: "motivational interviewing", questionType: "CASE_VIGNETTE" },
  { id: "sw-1369", stem: "In solution-focused therapy, the term 'not-knowing stance' means:", options: ["The therapist lacks professional training", "The therapist approaches each client with genuine curiosity, avoiding assumptions and allowing the client to be the expert on their own experience and solutions", "The therapist pretends not to understand the client's problems", "The therapist avoids using any theoretical framework"], correctIndex: 1, rationale: "The not-knowing stance in SFBT reflects the philosophical position that the client is the expert on their own life. The therapist maintains genuine curiosity, avoids imposing assumptions or expert interpretations, and uses questions to help the client discover their own solutions. This stance empowers clients and prevents the therapist from directing the therapeutic process based on their own agenda.", difficulty: 3, category: "Communication & Interviewing", topic: "solution-focused therapy", questionType: "MCQ" },
  { id: "sw-1370", stem: "A social worker observes that a hospital's discharge planning process consistently results in higher readmission rates for patients from racial minority communities. The PIE framework suggests this may be due to:", options: ["Individual patient non-compliance", "Systemic factors including implicit bias in discharge processes, language barriers, culturally incongruent service referrals, and structural inequities in community resource distribution", "Random variation in readmission rates", "Differences in disease severity only"], correctIndex: 1, rationale: "The person-in-environment framework directs attention to systemic and structural factors that contribute to health disparities. Disparate readmission rates suggest environmental and institutional barriers including implicit bias, language access gaps, culturally mismatched referrals, and inequitable distribution of community resources, rather than individual-level explanations alone.", difficulty: 5, category: "Interdisciplinary Collaboration", topic: "person-in-environment", questionType: "PRIORITIZATION" },
  { id: "sw-1371", stem: "A social worker applies the strengths perspective to documentation by:", options: ["Omitting all negative information from records", "Including client strengths, coping strategies, support systems, and progress alongside clinical concerns in assessment and progress notes to create a balanced, empowerment-oriented record", "Writing only positive comments about the client", "Avoiding documentation of challenges or barriers"], correctIndex: 1, rationale: "Strengths-based documentation includes strengths alongside challenges, creating a balanced clinical record that supports empowerment-oriented practice. This approach does not omit concerns but ensures that client capabilities, coping strategies, progress, and resources are systematically documented, informing strengths-based intervention planning and reflecting a holistic view of the client.", difficulty: 2, category: "Documentation & Record Keeping", topic: "strengths perspective", questionType: "MCQ" },
  { id: "sw-1372", stem: "A social worker advocates for policy changes that would expand Medicaid eligibility to cover more low-income adults. This is an example of:", options: ["Micro-level clinical practice", "Macro-level social justice advocacy addressing systemic barriers to healthcare access for economically marginalized populations", "Partisan political activity prohibited by the NASW Code of Ethics", "An individual case management strategy"], correctIndex: 1, rationale: "Advocating for Medicaid expansion addresses systemic healthcare access barriers affecting economically marginalized populations. This macro-level policy advocacy aligns with the NASW Code of Ethics' mandate to pursue social change, ensure equitable resource distribution, and challenge conditions that contribute to social problems and human suffering.", difficulty: 1, category: "Legislation & Policy Frameworks", topic: "social justice advocacy", questionType: "APPLIED_ETHICS" },
  { id: "sw-1373", stem: "A social worker must document a critical incident involving a client who made a suicide attempt. The documentation should include:", options: ["A brief note stating 'client attempted suicide' with no further detail", "A thorough factual account of the incident, risk assessment findings, clinical interventions performed, consultations obtained, safety planning, notifications made, and the rationale for all clinical decisions", "Only the outcome of the suicide attempt", "A copy of the client's suicide note if one was found"], correctIndex: 1, rationale: "Critical incident documentation must be thorough, factual, and timely. It should include the factual account, clinical assessment, interventions, consultations, safety planning, notifications, and clinical rationale for decisions made. This level of documentation supports continuity of care, demonstrates clinical competence, and provides legal protection for the practitioner and agency.", difficulty: 5, category: "Documentation & Record Keeping", topic: "mandated reporting", questionType: "PRIORITIZATION" },
  { id: "sw-1374", stem: "A clinical supervisor uses the developmental model to assess that a supervisee has progressed from dependence on the supervisor to a more autonomous practice style. The supervisor should now:", options: ["Maintain the same level of directive supervision", "Shift to a more consultative, collaborative supervisory approach that matches the supervisee's increased competence and confidence while continuing to provide support and challenge as needed", "Eliminate supervision entirely since the supervisee is competent", "Assign the supervisee to supervise others immediately"], correctIndex: 1, rationale: "Developmental supervision models prescribe that supervisory style should match the supervisee's developmental level. As supervisees gain competence and confidence, supervision shifts from directive (structured, instructive) to consultative (collaborative, autonomy-supporting). This progression maintains the supervisory relationship while appropriately supporting continued professional growth.", difficulty: 5, category: "Interdisciplinary Collaboration", topic: "supervision models", questionType: "CASE_VIGNETTE" },
  { id: "sw-1375", stem: "A social worker is asked to evaluate whether a community-based violence prevention program should receive continued funding. The MOST comprehensive evaluation approach would include:", options: ["Only interviewing program staff about their perceptions of success", "A mixed-methods design incorporating quantitative outcome data, qualitative participant experiences, cost-effectiveness analysis, fidelity assessment, and community-level impact indicators", "Only reviewing the program's attendance records", "A single satisfaction survey administered at program completion"], correctIndex: 1, rationale: "Comprehensive program evaluation for funding decisions requires multiple methods: quantitative outcome data to measure effectiveness, qualitative data to capture participant experiences and contextual factors, cost-effectiveness analysis to assess value, fidelity assessment to verify implementation quality, and community-level indicators to evaluate broader impact. This mixed-methods approach provides the most robust evidence for funding decisions.", difficulty: 5, category: "Community Practice & Advocacy", topic: "program evaluation", questionType: "PRIORITIZATION" },
];
